#include <iostream>
#include <algorithm>
using namespace std;
int main()
{
    int n,a[50005],b[50005],ans=0,la=1,lb=1;
    cin>>n;
    int ra=n,rb=n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
    }
    for(int i=1;i<=n;i++)
    {
        cin>>b[i];
    }
    sort(a+1,a+n+1);
    sort(b+1,b+n+1);
    for(int i=1;i<=n;i++)
    {
        if(a[ra]>b[rb])
        {
            ans++;
            ra--;
            rb--;
        }
        else if(a[ra]<b[rb])
        {
            la++;
            rb--;
        }
        else if(a[la]>b[lb])
        {
            ans++;
            la++;
            lb++;
        }
        else
        {
            la++;
            rb--;
        }
    }
    cout<<ans;
    return 0;
}
